noncompliant:
// Noncompliant: Function marked as noreturn but actually returns
[[noreturn]] int unexpectedReturn(int value) {
    if (value < 0) {
        exit(1);
    }
    return value;  // This violates the noreturn contract
}

// Another noncompliant example
[[noreturn]] void conditionalExit(bool shouldExit) {
    if (shouldExit) {
        std::terminate();
    }
    return;  // This should not return when marked as noreturn
}

// Noncompliant: Function sometimes returns despite noreturn attribute
[[noreturn]] void processError(const std::string& error) {
    if (error == "critical") {
        abort();
    }
    // Function continues and implicitly returns - violation
}

compliant:
// Compliant: Function truly never returns
[[noreturn]] void fatalError(int errorCode) {
    std::cerr << "Fatal error: " << errorCode << std::endl;
    exit(errorCode);
    // No return statement - function never returns
}

// Compliant: Function always terminates or throws
[[noreturn]] void handleCriticalFailure() {
    try {
        cleanup();
    } catch (...) {
        // Even if cleanup fails, we still terminate
    }
    std::terminate();  // Always terminates
}

// Compliant: Function that always throws
[[noreturn]] void throwError(const std::string& message) {
    throw std::runtime_error(message);
    // Execution never continues past the throw
}

// Compliant: Infinite loop function
[[noreturn]] void eventLoop() {
    while (true) {
        processEvents();
        std::this_thread::sleep_for(std::chrono::milliseconds(10));
    }
    // Never exits the loop
}
